lessons.solution:
function encontrarMaior(numeros: number[]): number {
  let maior: number = numeros[0];
  for (const num of numeros) {
    if (num > maior) {
      maior = num;
    }
  }
  return maior;
}

console.log(encontrarMaior([3, 7, 2, 9, 4]));
console.log(encontrarMaior([100]));
console.log(encontrarMaior([-5, -2, -8]));
